import{_ as a,o as i,c as t,ag as l}from"./chunks/framework.ePeAWSvT.js";const g=JSON.parse('{"title":"Changelog","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),r={name:"changelog.md"};function o(n,e,s,d,c,h){return i(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to this project will be documented in this file.</p><p>The format is based on <a href="https://keepachangelog.com/en/1.1.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>, and this project adheres to <a href="https://semver.org/spec/v2.0.0.html" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><h2 id="_0-3-1-alpha-1-2026-04-01" tabindex="-1"><a href="https://github.com/nicholasbester/aidis-releases/releases/tag/v0.3.1-alpha.1" target="_blank" rel="noreferrer">0.3.1-alpha.1</a> - 2026-04-01 <a class="header-anchor" href="#_0-3-1-alpha-1-2026-04-01" aria-label="Permalink to &quot;[0.3.1-alpha.1] - 2026-04-01&quot;">​</a></h2><p>Patch release fixing 13 config field mismatches found during QA testing.</p><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>IdentitySettings: use format/aieos fields instead of fabricated name/description</li><li>ObservabilitySection: backend, otel_endpoint, runtime_trace_mode (5 wrong fields replaced)</li><li>RuntimeSection: kind, reasoning_effort (removed streaming/max_tokens/timeout)</li><li>SecretsSection: encrypt only (removed 5 fabricated vault fields)</li><li>TunnelSection: nested provider-specific configs (ngrok/cloudflare/tailscale)</li><li>WebSearchSection: brave_api_key, searxng_instance_url (removed generic api_key/safe_search)</li><li>HeartbeatSection: interval_minutes not interval_secs</li><li>Mission analysis: use zeroclaw CLI instead of direct API calls (fixes encrypted key 401)</li><li>JSON extraction: brace-matching fallback for CLI response parsing</li><li>CI workflow: --legacy-peer-deps and xvfb-run for E2E</li></ul><h2 id="_0-3-0-alpha-1-2026-03-31" tabindex="-1"><a href="https://github.com/nicholasbester/aidis-releases/releases/tag/v0.3.0-alpha.1" target="_blank" rel="noreferrer">0.3.0-alpha.1</a> - 2026-03-31 <a class="header-anchor" href="#_0-3-0-alpha-1-2026-03-31" aria-label="Permalink to &quot;[0.3.0-alpha.1] - 2026-03-31&quot;">​</a></h2><p>Third alpha release — upgraded to zeroclaw 0.6.7 with full QA pass, config corrections, and new features for memory, auth, gateway, and diagnostics.</p><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><h4 id="new-pages" tabindex="-1">New Pages <a class="header-anchor" href="#new-pages" aria-label="Permalink to &quot;New Pages&quot;">​</a></h4><ul><li>Memory management page: list, get, stats, clear with category/session filtering and pagination</li><li>SOP page with graceful &quot;not available&quot; fallback for CLI versions without SOP support</li></ul><h4 id="new-settings-sections-28-total" tabindex="-1">New Settings Sections (28 total) <a class="header-anchor" href="#new-settings-sections-28-total" aria-label="Permalink to &quot;New Settings Sections (28 total)&quot;">​</a></h4><ul><li>Authentication: manage provider auth profiles (list, status, logout)</li><li>Triggers: webhook endpoints, rate limiting, MQTT broker configuration</li><li>Query Routing: classification rules with hint/keywords/priority</li><li>Sub-Agents: delegation configuration with provider/model/tools per agent</li><li>Skills Config: open-skills toggle, directory, prompt injection mode</li><li>Composio: OAuth tool integration</li><li>HTTP Requests: domain allowlist, size limits, timeout</li><li>Peripherals: board configuration with transport/path/baud</li><li>Security: OTP, E-Stop, sandbox, resource limits (corrected field names)</li></ul><h4 id="zeroclaw-0-6-7-integration" tabindex="-1">zeroclaw 0.6.7 Integration <a class="header-anchor" href="#zeroclaw-0-6-7-integration" aria-label="Permalink to &quot;zeroclaw 0.6.7 Integration&quot;">​</a></h4><ul><li>E-Stop: engage/status/resume with confirmation dialog and sidebar button</li><li>Diagnostics tab: doctor traces, model validation, self-test (quick/full)</li><li>Metrics dashboard widget</li><li>Service logs tailing with line count selector</li><li>Skills test runner and config schema viewer</li><li>Gateway management: restart, get/generate pairing codes</li><li>Agent <code>--peripheral</code> flag for hardware attachment in chat</li><li>CLI update check in General settings</li></ul><h4 id="error-handling-ux" tabindex="-1">Error Handling &amp; UX <a class="header-anchor" href="#error-handling-ux" aria-label="Permalink to &quot;Error Handling &amp; UX&quot;">​</a></h4><ul><li>React Error Boundary wrapping entire app</li><li>Global error handlers in main and renderer processes</li><li>Focus management on route changes</li><li>Improved empty states for skills and missions pages</li><li>Onboarding: channel skip guidance, &quot;What&#39;s next?&quot; section</li></ul><h4 id="testing-quality" tabindex="-1">Testing &amp; Quality <a class="header-anchor" href="#testing-quality" aria-label="Permalink to &quot;Testing &amp; Quality&quot;">​</a></h4><ul><li>1,180+ unit tests (up from 849)</li><li>Tests for all 28 settings sections</li><li>Tests for TagInput, ConfirmDialog, DiagnosticsTab, MemoryPage, AuthSection</li><li>Sidebar collapse persistence tests</li></ul><h4 id="performance-security" tabindex="-1">Performance &amp; Security <a class="header-anchor" href="#performance-security" aria-label="Permalink to &quot;Performance &amp; Security&quot;">​</a></h4><ul><li>React.memo on BudgetWidget, MetricsWidget, DiagnosticsTab, EstopButton</li><li>CSP headers refined: img-src, font-src, connect-src</li><li>Context menu disabled in production</li><li>webSecurity explicitly set</li></ul><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><strong>Settings crash</strong>: removed useBlocker (requires data router, incompatible with HashRouter)</li><li><strong>ANSI escape codes</strong>: stripped globally from all CLI output in runCommand()</li><li><strong>Config field mismatches</strong>: SecuritySection (sandbox, resources), CostSection (USD not cents), BrowserSection (native_headless), StorageSection (provider) — all corrected to match 0.6.7 schema</li><li><strong>Channel start</strong>: fixed to no-args call (0.6.7 starts ALL channels)</li><li><strong>E-Stop disabled state</strong>: shows &quot;Disabled&quot; instead of error when not enabled in config</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Upgraded zeroclaw CLI requirement from 0.1.0 to <strong>0.6.7</strong></li><li>Channel types expanded to 19 (added Nextcloud Talk, Linq, Nostr, MQTT, Feishu)</li><li>Chat overrides panel: added peripheral selector</li></ul><h2 id="_0-2-0-alpha-1-2026-03-15" tabindex="-1"><a href="https://github.com/nicholasbester/aidis-releases/releases/tag/v0.2.0-alpha.1" target="_blank" rel="noreferrer">0.2.0-alpha.1</a> - 2026-03-15 <a class="header-anchor" href="#_0-2-0-alpha-1-2026-03-15" aria-label="Permalink to &quot;[0.2.0-alpha.1] - 2026-03-15&quot;">​</a></h2><p>Second alpha release with major new features, security hardening, developer tooling, and expanded platform integration.</p><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><h4 id="missions" tabindex="-1">Missions <a class="header-anchor" href="#missions" aria-label="Permalink to &quot;Missions&quot;">​</a></h4><ul><li>Mission CRUD with JSON persistence</li><li>LLM-powered mission analysis with contribution planning</li><li>Workspace contribution applier with marker tracking</li><li>Mission detail page with overview and configuration tabs</li></ul><h4 id="settings-19-sections-3-new" tabindex="-1">Settings (19 sections, +3 new) <a class="header-anchor" href="#settings-19-sections-3-new" aria-label="Permalink to &quot;Settings (19 sections, +3 new)&quot;">​</a></h4><ul><li>Heartbeat section: interval and timeout configuration</li><li>Tunnel section: provider, auth token, subdomain</li><li>Service section: OS service install/start/stop/uninstall management</li><li>Config export and import with security warnings</li><li>Unsaved changes warning dialog on navigation</li><li>Input validation for host, port, model ID, and required fields</li><li>Confirmation dialogs for destructive actions</li></ul><h4 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h4><ul><li>Budget tracking tab with daily/monthly cost visualization</li><li>Daemon status banner in chat with start button</li></ul><h4 id="hardware" tabindex="-1">Hardware <a class="header-anchor" href="#hardware" aria-label="Permalink to &quot;Hardware&quot;">​</a></h4><ul><li>Hardware discovery page with USB device scanning</li><li>Peripheral listing and management</li></ul><h4 id="system-integration" tabindex="-1">System Integration <a class="header-anchor" href="#system-integration" aria-label="Permalink to &quot;System Integration&quot;">​</a></h4><ul><li><code>zeroclaw://</code> deep link protocol with path traversal protection</li><li>OS-level system notifications for background events</li><li>Auto-update mechanism via electron-updater (GitHub Releases)</li><li>Keyboard shortcuts (Cmd+S save, Cmd+, settings)</li><li>Quick navigation items in system tray menu</li><li>Window size/position persistence across restarts</li></ul><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h3><ul><li>Path traversal vulnerability fix in workspace file operations</li><li>Input validation for cron operations to prevent command injection</li><li>Restrictive file permissions on config and workspace files</li><li>MCP <code>app_eval</code> tool gated behind <code>ZEROCLAW_MCP_ALLOW_EVAL</code> env var</li></ul><h3 id="accessibility" tabindex="-1">Accessibility <a class="header-anchor" href="#accessibility" aria-label="Permalink to &quot;Accessibility&quot;">​</a></h3><ul><li>ARIA labels on sidebar navigation and collapse button</li><li>ARIA live regions for daemon status, save feedback, and chat banner</li><li>Icons on daemon status badges for color-blind users</li></ul><h3 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h3><ul><li>Dashboard refresh cooldown to prevent redundant API calls</li><li>Memoized log filtering to avoid refiltering on every render</li><li>Marketplace cache freshness check before fetching catalog</li><li>Dashboard timestamp re-render reduced from 1s to 30s interval</li></ul><h3 id="developer-experience" tabindex="-1">Developer Experience <a class="header-anchor" href="#developer-experience" aria-label="Permalink to &quot;Developer Experience&quot;">​</a></h3><ul><li>ESLint 9 with React, hooks, a11y, and TypeScript plugins</li><li>Prettier with husky pre-commit hooks and lint-staged</li><li><code>type-check</code>, <code>test:coverage</code>, and <code>validate</code> npm scripts</li><li>CI pipeline: lint, type-check, format-check, and coverage checks</li><li>Automated accessibility testing with vitest-axe</li></ul><h3 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h3><ul><li>849+ unit tests with expanded coverage</li><li>Tests for AI assist IPC, tray module, missions, chat daemon status, hardware, and more</li></ul><h3 id="fixed-2" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-2" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Updated zeroclaw repo links from openagen to zeroclaw-labs</li><li>Synced latest zeroclaw documentation</li></ul><h2 id="_0-1-0-alpha-1-2026-02-25" tabindex="-1"><a href="https://github.com/nicholasbester/aidis-releases/releases/tag/v0.1.0-alpha.1" target="_blank" rel="noreferrer">0.1.0-alpha.1</a> - 2026-02-25 <a class="header-anchor" href="#_0-1-0-alpha-1-2026-02-25" aria-label="Permalink to &quot;[0.1.0-alpha.1] - 2026-02-25&quot;">​</a></h2><p>First alpha release of ZeroClaw UI — a desktop management interface for the <a href="https://gitlab.com/zeroclaw-labs/zeroclaw" target="_blank" rel="noreferrer">zeroclaw</a> AI agent platform.</p><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><h4 id="core-application" tabindex="-1">Core Application <a class="header-anchor" href="#core-application" aria-label="Permalink to &quot;Core Application&quot;">​</a></h4><ul><li>Electron 40 + React 19 desktop app with Vite-based build system</li><li>Preload script with typed IPC bridge and context isolation</li><li>System tray integration with daemon status indicator</li><li>Dark mode support with system theme sync</li><li>Single-instance enforcement</li><li>MCP server for Claude Code integration (daemon management, CDP debug tools)</li></ul><h4 id="onboarding" tabindex="-1">Onboarding <a class="header-anchor" href="#onboarding" aria-label="Permalink to &quot;Onboarding&quot;">​</a></h4><ul><li>4-step setup wizard: detect installation, provider setup, channel config, test connection</li><li>First-run detection with automatic daemon startup</li></ul><h4 id="dashboard-1" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard-1" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h4><ul><li>Operations dashboard with status, doctor, channels, scheduler, and logs tabs</li><li>Real-time daemon status polling (start/stop/restart)</li><li>Log viewer with real-time streaming</li><li>Channel health diagnostics</li></ul><h4 id="settings-16-sections" tabindex="-1">Settings (16 sections) <a class="header-anchor" href="#settings-16-sections" aria-label="Permalink to &quot;Settings (16 sections)&quot;">​</a></h4><ul><li>General (provider, model, temperature, API key)</li><li>Identity, Gateway, Memory, Channels, Model Routes</li><li>Scheduler with visual cron job builder</li><li>Autonomy, Runtime, Multimodal, Cost &amp; Limits</li><li>Observability, Browser, Web Search, Storage, Secrets</li><li>SaveBar with TOML serialization, validation via <code>zeroclaw doctor</code>, and daemon restart</li><li>Window focus config reload for concurrent editing support</li></ul><h4 id="agent-editor-7-sections" tabindex="-1">Agent Editor (7 sections) <a class="header-anchor" href="#agent-editor-7-sections" aria-label="Permalink to &quot;Agent Editor (7 sections)&quot;">​</a></h4><ul><li>Workspace file editor for Identity, Soul, Agent Definition, User, Memory, Heartbeat, Tools</li><li>Markdown editor with edit/view toggle</li><li>AI-assisted content generation dialog with user prompts</li><li>Dirty tracking with save bar</li></ul><h4 id="skills-marketplace" tabindex="-1">Skills Marketplace <a class="header-anchor" href="#skills-marketplace" aria-label="Permalink to &quot;Skills Marketplace&quot;">​</a></h4><ul><li>Installed skills tab with remove functionality</li><li>Marketplace tab with search and category filtering</li><li>Bulk install with progress tracking and retry logic</li></ul><h4 id="chat" tabindex="-1">Chat <a class="header-anchor" href="#chat" aria-label="Permalink to &quot;Chat&quot;">​</a></h4><ul><li>Message-based chat interface for testing agent responses</li><li>Markdown rendering for agent replies</li><li>ANSI stripping from CLI output</li></ul><h4 id="documentation-site" tabindex="-1">Documentation Site <a class="header-anchor" href="#documentation-site" aria-label="Permalink to &quot;Documentation Site&quot;">​</a></h4><ul><li>VitePress-powered docs site with GitHub Pages deployment</li><li>Setup guide and contributor information</li></ul><h3 id="testing-1" tabindex="-1">Testing <a class="header-anchor" href="#testing-1" aria-label="Permalink to &quot;Testing&quot;">​</a></h3><ul><li>637+ unit tests (Vitest) with 87% code coverage</li><li>9 Playwright E2E test files covering all pages and key interactions</li><li>Coverage thresholds: 85% statements/lines, 80% branches, 60% functions</li></ul><h3 id="ci-cd" tabindex="-1">CI/CD <a class="header-anchor" href="#ci-cd" aria-label="Permalink to &quot;CI/CD&quot;">​</a></h3><ul><li>GitHub Actions pipeline for unit tests and E2E tests on PRs and pushes to main/develop</li><li>Automated docs site deployment to GitHub Pages</li></ul><h3 id="known-issues" tabindex="-1">Known Issues <a class="header-anchor" href="#known-issues" aria-label="Permalink to &quot;Known Issues&quot;">​</a></h3><ul><li>See <a href="https://github.com/nicholasbester/aidis/issues" target="_blank" rel="noreferrer">open issues</a> for the full list</li><li>Emergency stop (E-Stop) UI not yet implemented</li><li>SOP management not yet in UI</li><li>6 channel types not yet configurable (Nextcloud Talk, Linq, Nostr, MQTT, Feishu, CLI)</li></ul>',76)])])}const p=a(r,[["render",o]]);export{g as __pageData,p as default};
